   410→        icon: 'error',
   411→        message: error instanceof Error ? error.message : 'Failed to reschedule PM',
   412→        timeout: 5000,
   413→      });
   414→    } finally {
   415→      // Close dialog and clear state
   416→      dragConfirmRef.current = initialDragConfirmState;
   417→      draggingPmRef.current = null;
   418→    }
   419→  };
