     1→/**
     2→ * Detail Card Overlay
     3→ *
     4→ * React DOM overlay for the detail view (zoom levels 16+).
     5→ * Provides rich PM editing interfaces with:
     6→ * - Full PM details in expandable cards
     7→ * - Inline editing (date, depot, track, shift)
     8→ * - Crew assignment display
     9→ * - Material status with availability badges
    10→ * - Compliance window timeline visualization
    11→ * - Change history panel
    12→ * - Real-time constraint validation feedback
    13→ *
    14→ * Uses BlueprintJS components for consistent UI.
    15→ * State managed via @belt/tools (no React hooks).
    16→ *
    17→ * @see specs/006-user-interface.md Section 6.3.4, 6.3.5
    18→ */
    19→
    20→import { useRef } from 'react';
    21→import {
    22→  Card,
    23→  Elevation,
    24→  Tag,
    25→  Intent,
    26→  Button,
    27→  ButtonGroup,
    28→  Collapse,
    29→  Icon,
    30→  ProgressBar,
    31→  Divider,
    32→  HTMLTable,
    33→  Tooltip,
    34→  Position,
    35→  Popover,
    36→  Menu,
    37→  MenuItem,
    38→  MenuDivider,
    39→} from '@blueprintjs/core';
    40→
    41→import type { OperationalPmBlock, OperationalCanvasData, MaterialStatus } from './types';
    42→import { PM_STATUS_COLORS, CONSTRAINT_COLORS, FLEET_COLORS } from '../../theme/colors';
    43→
    44→// =============================================================================
    45→// Types
    46→// =============================================================================
    47→
    48→export interface DetailPmBlock extends OperationalPmBlock {
    49→  /** Change history for audit trail */
    50→  changeHistory?: ChangeHistoryEntry[];
    51→  /** Constraint validation results */
    52→  constraintValidation?: DetailConstraintValidation;
    53→  /** Assigned crew (if available) */
    54→  assignedCrew?: CrewAssignment[];
    55→}
    56→
    57→export interface ChangeHistoryEntry {
    58→  id: string;
    59→  timestamp: string;
    60→  changeType: 'CREATE' | 'MOVE' | 'REASSIGN' | 'LOCK' | 'UNLOCK' | 'STATUS_CHANGE';
    61→  field?: string;
    62→  oldValue?: string;
    63→  newValue?: string;
    64→  userId: string;
    65→  userName: string;
    66→  reason?: string;
    67→}
    68→
    69→export interface DetailConstraintValidation {
    70→  isValid: boolean;
    71→  violations: DetailConstraintViolation[];
    72→  warnings: DetailConstraintWarning[];
    73→}
    74→
    75→export interface DetailConstraintViolation {
    76→  type: 'HARD' | 'SOFT';
    77→  constraint: string;
    78→  message: string;
    79→  canOverride: boolean;
    80→}
    81→
    82→export interface DetailConstraintWarning {
    83→  type: string;
    84→  message: string;
    85→}
    86→
    87→export interface CrewAssignment {
    88→  crewId: string;
    89→  crewName: string;
    90→  role: string;
    91→  shift: string;
    92→}
    93→
    94→export interface DetailCanvasData extends OperationalCanvasData {
    95→  pmBlocks: DetailPmBlock[];
    96→}
    97→
    98→export interface DetailCardOverlayProps {
    99→  data: DetailCanvasData | null;
   100→  fromDate: Date;
   101→  toDate: Date;
   102→  width: number;
   103→  height: number;
   104→  selectedPmIds?: string[];
   105→  expandedPmIds?: string[];
   106→  onPmSelect?: (pmId: string) => void;
   107→  onPmExpand?: (pmId: string) => void;
   108→  onPmCollapse?: (pmId: string) => void;
   109→  onPmEdit?: (pmId: string, field: string, value: unknown) => void;
   110→  onPmLock?: (pmId: string) => void;
