   149→function getPmStatusColor(status: string): string {
   150→  const normalizedStatus = status.toLowerCase().replace('_', '') as keyof typeof PM_STATUS_COLORS;
   151→  return PM_STATUS_COLORS[normalizedStatus] ?? PM_STATUS_COLORS.scheduled;
   152→}
