   342→
   343→// =============================================================================
   344→// Async PM Slice
   345→// =============================================================================
   346→
   347→export interface PmApiResponse {
   348→  schedule: PmScheduleEntry[];
   349→  types: PmType[];
   350→}
   351→
   352→export const pmAsyncSlice = createAsyncSlice({
   353→  id: 'pmApi',
   354→  cache: {
   355→    policy: 'public',
   356→    ttl: '2m',
   357→    swr: true,
   358→  },
   359→  context: {
   360→    baseUrl: '/api/v1',
   361→    startDate: new Date().toISOString().split('T')[0],
   362→    endDate: new Date(Date.now() + 84 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
   363→  },
   364→  load: async (ctx) => {
   365→    const { baseUrl, startDate, endDate } = ctx as {
   366→      baseUrl: string;
   367→      startDate: string;
   368→      endDate: string;
   369→    };
   370→
   371→    const [scheduleRes, typesRes] = await Promise.all([
   372→      fetch(`${baseUrl}/pm/schedule?startDate=${startDate}&endDate=${endDate}&pageSize=1000`),
   373→      fetch(`${baseUrl}/pm/types`),
   374→    ]);
   375→
   376→    if (!scheduleRes.ok || !typesRes.ok) {
   377→      throw new Error('Failed to fetch PM data');
   378→    }
   379→
   380→    const [scheduleData, typesData] = await Promise.all([
   381→      scheduleRes.json() as Promise<{ data: PmScheduleEntry[] }>,
   382→      typesRes.json() as Promise<{ data: PmType[] }>,
   383→    ]);
   384→
   385→    return {
   386→      schedule: scheduleData.data,
   387→      types: typesData.data,
   388→    };
   389→  },
   390→});
   391→
   392→// =============================================================================
   393→// Selectors
   394→// =============================================================================
   395→
   396→export function selectPmById(state: PmSliceState, pmId: string): PmScheduleEntry | undefined {
   397→  return state.pmSchedule.find((p) => p.id === pmId);
   398→}
   399→
   400→export function selectPmsByTrain(state: PmSliceState, trainId: string): PmScheduleEntry[] {
   401→  return state.pmSchedule.filter((p) => p.trainId === trainId);
   402→}
   403→
   404→export function selectPmsInRange(
   405→  state: PmSliceState,
   406→  startDate: string,
   407→  endDate: string
   408→): PmScheduleEntry[] {
   409→  return state.pmSchedule.filter((p) => p.targetDate >= startDate && p.targetDate <= endDate);
   410→}
   411→
   412→export function selectLockedPmCount(state: PmSliceState): number {
   413→  return Object.keys(state.lockedPmIds).length;
   414→}
   415→
   416→export function isPmBeingDragged(state: PmSliceState, pmId: string): boolean {
   417→  return state.drag.isDragging && state.drag.pmId === pmId;
   418→}
   419→
   420→export function hasPendingMove(state: PmSliceState, pmId: string): boolean {
   421→  return pmId in state.pendingMoves;
   422→}
   423→
   424→export function selectPmTypeById(state: PmSliceState, typeId: string): PmType | undefined {
   425→  return state.pmTypes.find((t) => t.id === typeId);
   426→}
   427→
   428→export function selectPmStats(state: PmSliceState): {
   429→  total: number;
   430→  scheduled: number;
   431→  inProgress: number;
   432→  completed: number;
   433→  deferred: number;
   434→  cancelled: number;
   435→  locked: number;
   436→} {
   437→  const schedule = state.pmSchedule;
   438→  return {
   439→    total: schedule.length,
   440→    scheduled: schedule.filter((p) => p.status === 'SCHEDULED').length,
   441→    inProgress: schedule.filter((p) => p.status === 'IN_PROGRESS').length,
   442→    completed: schedule.filter((p) => p.status === 'COMPLETED').length,
   443→    deferred: schedule.filter((p) => p.status === 'DEFERRED').length,
   444→    cancelled: schedule.filter((p) => p.status === 'CANCELLED').length,
   445→    locked: Object.keys(state.lockedPmIds).length,
   446→  };
   447→}
   448→
   449→export function selectPmsWithViolations(
   450→  state: PmSliceState
   451→): Array<{ pm: PmScheduleEntry; violations: ConstraintViolation[] }> {
   452→  const result: Array<{ pm: PmScheduleEntry; violations: ConstraintViolation[] }> = [];
   453→
   454→  state.pmSchedule.forEach((pm) => {
   455→    const cacheKey = `${pm.id}:${pm.targetDate}`;
   456→    const violations = state.constraintCache[cacheKey];
   457→    if (violations && violations.length > 0) {
   458→      result.push({ pm, violations });
   459→    }
   460→  });
   461→
   462→  return result;
   463→}
